        getLanguageFlagSvg(lang) {
            if (lang === 'en') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 60 30" width="20" height="14" aria-hidden="true"><path d="M0,0 v30 h60 v-30 z" fill="#012169"/><path d="M0,0 L60,30 M60,0 L0,30" stroke="#fff" stroke-width="6"/><path d="M0,0 L60,30 M60,0 L0,30" stroke="#C8102E" stroke-width="4"/><path d="M30,0 v30 M0,15 h60" stroke="#fff" stroke-width="10"/><path d="M30,0 v30 M0,15 h60" stroke="#C8102E" stroke-width="6"/></svg>';
            }
            if (lang === 'de') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 9 6" width="20" height="14" aria-hidden="true"><rect fill="#21468B" width="9" height="6"/><rect fill="#FFF" width="9" height="4"/><rect fill="#AE1C28" width="9" height="2"/></svg>';
            }
            if (lang === 'fr') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 900 600" width="20" height="14" aria-hidden="true"><rect width="900" height="600" fill="#CE1126"/><rect width="600" height="600" fill="#FFFFFF"/><rect width="300" height="600" fill="#002654"/></svg>';
            }
            if (lang === 'he') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1100 800" width="20" height="14" aria-hidden="true"><path fill="#fff" d="M0,0H1100V800H0Z"/><path fill="#0038b8" d="M0,75H1100V200H0Z"/><path fill="#0038b8" d="M0,600H1100V725H0Z"/><path fill="none" stroke="#0038b8" stroke-width="27.5" d="M423.81566,472.85253H676.18435L550.00001,254.29492Zm126.18435,72.85255l126.1843-218.55765H423.81566Z"/></svg>';
            }
            if (lang === 'ru') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 9 6" width="20" height="14" aria-hidden="true"><rect width="9" height="6" fill="#D52B1E"/><rect y="2" width="9" height="2" fill="#0039A6"/><rect y="0" width="9" height="2" fill="#fff"/></svg>';
            }
            if (lang === 'ar') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 12 6" width="20" height="14" aria-hidden="true"><rect width="12" height="6" fill="#00843d"/><rect width="12" height="4" y="2" fill="#fff"/><rect width="12" height="2" y="4" fill="#000"/><rect width="3" height="6" fill="#c8102e"/></svg>';
            }
            if (lang === 'es') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 4 3" width="20" height="14" aria-hidden="true"><rect width="4" height="3" fill="#AA151B"/><rect y="0.75" width="4" height="1.5" fill="#F1BF00"/></svg>';
            }
            if (lang === 'pt') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 5 3" width="20" height="14" aria-hidden="true"><rect width="2" height="3" fill="#006600"/><rect x="2" width="3" height="3" fill="#DA291C"/></svg>';
            }
            if (lang === 'it') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 3 2" width="20" height="14" aria-hidden="true"><rect width="1" height="2" fill="#009246"/><rect x="1" width="1" height="2" fill="#fff"/><rect x="2" width="1" height="2" fill="#ce2b37"/></svg>';
            }
            if (lang === 'tw') {
                return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 6 4" width="20" height="14" aria-hidden="true"><rect width="6" height="4" fill="#fe0000"/><rect width="3" height="2" fill="#000094"/><circle cx="1.5" cy="1" r="0.5" fill="#fff"/></svg>';
            }
            return null;
        }
    
        createLanguageDropdownElements(container) {
            // Clear container
            while (container.firstChild) {
                container.removeChild(container.firstChild);
            }
            
            const dropdownContent = document.createElement('div');
            dropdownContent.className = 'language-dropdown-content';
            
            const languages = [
                { lang: 'en', flag: '🇺🇸', name: 'English', label: 'Select English language' },
                { lang: 'de', flag: '🇩🇪', name: 'Deutsch', label: 'Select German language' },
                { lang: 'fr', flag: '🇫🇷', name: 'Français', label: 'Select French language' },
                { lang: 'he', flag: '🇮🇱', name: 'עברית', label: 'Select Hebrew language' },
                { lang: 'ru', flag: '🇷🇺', name: 'Русский', label: 'Select Russian language' },
                { lang: 'ar', flag: '🇦🇪', name: 'العربية', label: 'Select Arabic language' },
                { lang: 'es', flag: '🇪🇸', name: 'Español', label: 'Select Spanish language' },
                { lang: 'pt', flag: '🇵🇹', name: 'Português', label: 'Select Portuguese language' },
                { lang: 'it', flag: '🇮🇹', name: 'Italiano', label: 'Select Italian language' },
                { lang: 'tw', flag: '🇹🇼', name: '繁體中文', label: 'Select Traditional Chinese language' }
            ];
            
            languages.forEach(langData => {
                const button = document.createElement('button');
                button.className = 'language-option';
                button.setAttribute('data-lang', langData.lang);
                button.setAttribute('data-flag', langData.flag);
                button.setAttribute('tabindex', '0');
                button.setAttribute('role', 'option');
                button.setAttribute('aria-label', langData.label);
                
                const flagSpan = document.createElement('span');
                flagSpan.className = 'flag';
                const flagSvg = this.getLanguageFlagSvg(langData.lang);
                if (flagSvg) {
                    flagSpan.innerHTML = flagSvg;
                } else {
                    flagSpan.textContent = langData.flag;
                }
                button.appendChild(flagSpan);
                
                const nameSpan = document.createElement('span');
                nameSpan.className = 'language-name';
                nameSpan.textContent = langData.name;
                button.appendChild(nameSpan);
                
                dropdownContent.appendChild(button);
            });
            
            container.appendChild(dropdownContent);
        }
    
    
    
