        togglePanel() {
    
            
    
            const panel = this.shadowRoot.getElementById('accessbit-widget-panel');
    
            
    
            if (panel) {
    
                
    
                
    
                
    
                
    
                if (panel.classList.contains('active')) {
    
                    panel.classList.remove('active');
                    document.body.classList.remove('accessbit-panel-open');
    
                    
                    
                    // Re-enable smooth scrolling libraries when panel is closed
                    this.enableSmoothScrollingLibraries();
    
                } else {
    
                    this.ensureGreylayerStyle();
                    document.body.classList.add('accessbit-panel-open');
                    panel.classList.add('active');
    
                    
                    
                    // Fix scrolling conflicts with GSAP/Lenis libraries
                    setTimeout(() => {
                        this.fixPanelScrolling();
                    }, 100);
    
                }
    
                
    
                
    
                
    
                
    
                // Force a repaint
    
                panel.offsetHeight;
    
            } else {
    
                
    
            }
    
        }
    
        /** If the user disabled a feature that triggers a reload (e.g. light contrast), reopen the panel after load. Flag is set before reload and cleared here so we only reopen once. */
        reopenPanelAfterLoadIfRequested() {
            try {
                if (sessionStorage.getItem('accessbit-open-panel-after-load') !== '1') return;
                sessionStorage.removeItem('accessbit-open-panel-after-load');
                const panel = this.shadowRoot && this.shadowRoot.getElementById('accessbit-widget-panel');
                if (panel && !panel.classList.contains('active')) {
                    this._reopenAfterLoadNoFocus = true;
                    this.togglePanel();
                }
            } catch (_) {}
        }
    
    
    
        showStatement() {
            // Check if we have a custom accessibility statement link
            if (this.customizationData && this.customizationData.accessibilityStatementLink) {
                // Validate the link before opening
                const link = this.customizationData.accessibilityStatementLink.trim();
                if (link !== '') {
                    window.open(link, '_blank');
                    return;
                }
            }
            
            // Default statement if no link is provided
            const message = 'Accessibility Statement: This website is committed to providing an accessible experience for all users. We follow WCAG 2.1 guidelines and continuously work to improve accessibility.';
            alert(message);
        }
    
        
    
        
    
        
    
        
    
