        // Content Scaling Methods
    
        increaseContentScale() {
            
            this.contentScale = Math.min(this.contentScale + 2, 120); // 2% increment, max 120%
            this.settings['content-scale'] = this.contentScale;
            
            // Mark content scaling as used
            localStorage.setItem('content-scaling-used', 'true');
            
            
            this.updateContentScale();
            this.updateContentScaleDisplay();
            this.saveSettings();
        }
        
        decreaseContentScale() {
          
            this.contentScale = Math.max(this.contentScale - 2, 50); // 2% decrement, minimum 50%
            this.settings['content-scale'] = this.contentScale;
            
            // Mark content scaling as used
            localStorage.setItem('content-scaling-used', 'true');
            
  
            this.updateContentScale();
            this.updateContentScaleDisplay();
            this.saveSettings();
        }
        
        updateContentScale() {
            const body = document.body;

            // Hard safety: normalize value every time before computing zoom.
            const raw = Number(this.contentScale);
            const normalized = Number.isFinite(raw) ? Math.round(raw) : 100;
            const safePercent = Math.min(150, Math.max(50, normalized));
            if (safePercent !== this.contentScale) {
                this.contentScale = safePercent;
                if (this.settings) this.settings['content-scale'] = safePercent;
            }
            
            // If content scale is 100%, reset to normal
            if (this.contentScale === 100) {
                // Remove any existing content scaling CSS
                const existingStyle = document.getElementById('content-scaling-styles');
                if (existingStyle) {
                    existingStyle.remove();
                }
                
                // Reset widget elements to normal size
                this.resetWidgetScale();
                
                return;
            }
            
            // Create or update CSS that scales content without breaking layouts
            let style = document.getElementById('content-scaling-styles');
            if (!style) {
                style = document.createElement('style');
                style.id = 'content-scaling-styles';
                document.head.appendChild(style);
            }
            
            const scale = this.contentScale / 100;
            const inverseScale = 1 / scale;
            const safeInverse = Number.isFinite(inverseScale) ? Math.min(2, Math.max(0.6667, inverseScale)) : 1;
            
            style.textContent = `
                /* Content scaling using zoom - works in Chrome, Safari, Edge, Firefox 110+ */
                html {
                    zoom: ${scale} !important;
                }
                
                /* Ensure body and html can scroll properly */
                html, body {
                    overflow-x: hidden !important;
                    overflow-y: auto !important;
                }

                /* Prevent widget container and panel from being scaled by content scaling */
                #accessbit-widget-container,
                #accessbit-widget,
                [id*="accessbit-widget"],
                .accessbit-widget-panel,
                #accessbit-widget-icon {
                    zoom: ${safeInverse} !important;
                    transition: none !important;
                    will-change: auto !important;
                    contain: layout style !important;
                    isolation: isolate !important;
                }
            `;
            
            // Counter-scale widget from inside Shadow DOM so host is unaffected by html zoom
            this.applyWidgetCounterScale(safeInverse);
        }
        
        // Apply counter-scaling to widget elements to maintain fixed size
        applyWidgetCounterScale(inverseScale) {
            if (!this.shadowRoot) return;
            const safeInverse = Number.isFinite(Number(inverseScale)) ? Math.min(2, Math.max(0.6667, Number(inverseScale))) : 1;
            
            // Inject counter-scaling styles into Shadow DOM
            let counterStyle = this.shadowRoot.getElementById('content-scaling-counter');
            if (!counterStyle) {
                counterStyle = document.createElement('style');
                counterStyle.id = 'content-scaling-counter';
                this.shadowRoot.appendChild(counterStyle);
            }
            
            // Use zoom on host so the entire widget (host + shadow contents) counter-scales; inner elements stay 1:1
            counterStyle.textContent = `
                :host {
                    zoom: ${safeInverse} !important;
                    transition: none !important;
                    contain: layout style !important;
                    isolation: isolate !important;
                }
                #accessbit-widget-panel,
                #accessbit-widget-icon {
                    zoom: 1 !important;
                    transition: none !important;
                    will-change: auto !important;
                }
                #accessbit-widget-panel {
                    min-height: auto !important;
                    height: auto !important;
                }
            `;
        }
        
        // Reset widget scale when content scaling is disabled
        resetWidgetScale() {
            if (!this.shadowRoot) return;
            
            // Remove counter-scaling styles
            const counterStyle = this.shadowRoot.getElementById('content-scaling-counter');
            if (counterStyle) {
                counterStyle.remove();
            }
        }
        
        updateContentScaleDisplay() {
            const display = this.shadowRoot.getElementById('content-scale-value');
            if (display) {
                display.textContent = this.contentScale + '%';
            }
            const rangeEl = this.shadowRoot.getElementById('content-scale-range');
            if (rangeEl) {
                rangeEl.value = String(Math.min(150, Math.max(50, this.contentScale)));
                this.updateScalingThumbPosition(rangeEl);
            }
        }
        updateScalingThumbPosition(rangeEl) {
            if (!rangeEl || !rangeEl.closest) return;
            const track = rangeEl.closest('.scaling-slider-track');
            const thumb = track ? track.querySelector('.scaling-slider-thumb') : null;
            if (!thumb) return;
            const min = parseFloat(rangeEl.getAttribute('min')) || 0;
            const max = parseFloat(rangeEl.getAttribute('max')) || 100;
            const value = parseFloat(rangeEl.value) || 100;
            const leftPercent = (value - min) / (max - min) * 100;
            const trackDir = (track && track.getAttribute('dir')) || 'ltr';
            const finalPercent = trackDir === 'rtl' ? 100 - leftPercent : leftPercent;
            const pct = Math.max(0, Math.min(100, finalPercent));
            thumb.style.left = pct + '%';
            thumb.style.removeProperty('right');
            thumb.style.removeProperty('transform');
        }
        
        toggleContentScalingControls(enabled) {
            const controls = this.shadowRoot.getElementById('content-scaling-controls');
            if (controls) {
                controls.style.display = enabled ? 'block' : 'none';
            }
            const contentScaleRange = this.shadowRoot.getElementById('content-scale-range');
            if (contentScaleRange) {
                contentScaleRange.value = String(Math.min(150, Math.max(50, this.contentScale)));
            }
            if (enabled) {
                this.updateContentScaleDisplay();
                this.updateScalingThumbPosition(contentScaleRange);
                if (this.contentScale !== 100) {
                    this.updateContentScale();
                }
            } else {
                // Reset content scale when disabled
                this.contentScale = 100;
                this.settings['content-scale'] = 100;
                this.updateContentScale();
                this.saveSettings();
            }
        }
    
    
    
